package be.schaubroeck.lpb.rkm.rekenmotor.factory;

import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.WerkbonusLuik;
import be.schaubroeck.lpb.rkm.rekenmotor.service.ExtraSqlService;
import be.schaubroeck.lpb.rkm.rekenmotor.datamanager.PersoonsDataManagerImp;
import be.schaubroeck.lpb.tools.Admin;
import be.schaubroeck.lpb.tools.enumtypes.RekenBedragType;
import be.schaubroeck.temporal.interval.LocalDateInterval;
import be.schaubroeck.temporal.interval.Quarter;
import com.google.common.collect.Ordering;
import lombok.AllArgsConstructor;
import org.joda.time.LocalDate;

import java.util.ArrayList;
import java.util.List;

@AllArgsConstructor
public class BepaalWerkbonusOverdrachtData {

    public static final LocalDate START_OVERDRACHTEN_WERKBONUS_BUITEN_KWARTAAL = new LocalDate(2026, 1, 1);

    private ExtraSqlService extraSqlService;

    public void bepaal(Admin admin, Integer persoonId, RekenTijd rekenTijd, PersoonsDataManagerImp dataManager) {
        List<ExtraSqlService.OverdrachtData> overdrachtDatas = findOverdrachten(admin, persoonId, rekenTijd.beginDatum);
        for (ExtraSqlService.OverdrachtData overdrachtData : overdrachtDatas) {
            if (overdrachtData.getRekenBedragType() == RekenBedragType.WERKBONUS_LAGE_LONEN) {
                dataManager.addWerkbonusOverdracht(WerkbonusLuik.LUIK_A, overdrachtData.getOpdrachtNr(), overdrachtData.getBedrag());
            } else if (overdrachtData.getRekenBedragType() == RekenBedragType.WERKBONUS_HEEL_LAGE_LONEN) {
                dataManager.addWerkbonusOverdracht(WerkbonusLuik.LUIK_B, overdrachtData.getOpdrachtNr(), overdrachtData.getBedrag());
            }
        }
    }

    private List<ExtraSqlService.OverdrachtData> findOverdrachten(Admin admin, Integer persoonId, LocalDate selectieDatum) {
        if (selectieDatum.isBefore(START_OVERDRACHTEN_WERKBONUS_BUITEN_KWARTAAL)) {
            return extraSqlService.findOverdrachten(admin, persoonId, selectieDatum);
        } else if (!selectieDatum.minusDays(1).isBefore(START_OVERDRACHTEN_WERKBONUS_BUITEN_KWARTAAL)) {
            Quarter kwartaal = new Quarter(selectieDatum);
            LocalDate startPeriod = kwartaal.getEnd().minusYears(1).plusDays(1);
            startPeriod = Ordering.natural().max(startPeriod, START_OVERDRACHTEN_WERKBONUS_BUITEN_KWARTAAL);
            LocalDateInterval periode = new LocalDateInterval(startPeriod, selectieDatum.minusDays(1));
            return extraSqlService.findOverdrachtenPeriode(admin, persoonId, periode);
        } else {
            return new ArrayList<>();
        }
    }
}
